using System.Collections;
using System.Collections.Generic;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Menu de Pausa ("+" — Tarefa #35 restructurado): atalho directo para
/// <see cref="OptionsSectionUI"/>. Abre com "+"
/// (<see cref="PlayerInputRouter.PausePressed"/>), pausa via
/// <see cref="GamePauseUtil"/>.
///
/// Após a restructuração (#35), "+" abre <b>apenas Opções</b>. Todas as outras
/// secções (Área, Diário, Formas, Itens, Progresso, Emblemas, Upgrades) estão
/// no <see cref="SecondaryMenuController"/> ("-").
///
/// O framework de múltiplas secções mantém-se intacto (é extensível), mas em
/// produção <c>sectionBehaviours</c> deve conter <b>apenas</b>
/// <c>OptionsSectionUI</c> — a navegação L/R fica inactiva com uma única secção.
///
/// - Cabeçalho: nome do mundo, nome da área, % de conclusão, ícone do animal.
/// - "B"/Escape e "+" fecham.
/// - Animação escala+fade (~0.25-0.35s).
/// - Enquanto aberto: BGM abafado (SetBgmMuffled).
///
/// Montagem no Editor:
/// - "panelRoot"/"canvasGroup"/"animatedRoot": painel e animação.
/// - Cabeçalho: "worldNameText", "areaNameText", "areaPercentText", "equippedAnimalIcon".
/// - "sectionBehaviours": colocar apenas <c>OptionsSectionUI</c>.
/// - "sectionLabels": pode ter um único label "OPÇÕES", ou ficar vazio.
/// </summary>
public class PauseMenuController : MonoBehaviour
{
    public static PauseMenuController Instance { get; private set; }

    [Header("Painel")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private CanvasGroup canvasGroup;
    [SerializeField] private RectTransform animatedRoot;

    [Header("Animação de Abertura/Fecho")]
    [Tooltip("Duração da animação de abrir/fechar, em segundos (GDD: 0.25 a 0.35s).")]
    [SerializeField] private float animDuration = 0.3f;

    [Tooltip("Escala inicial (ao abrir) / final (ao fechar) do painel — efeito de \"abrir como uma folha/pedra rúnica\".")]
    [SerializeField] private float closedScale = 0.85f;

    [Header("Cabeçalho")]
    [SerializeField] private TMP_Text worldNameText;
    [SerializeField] private TMP_Text areaNameText;
    [SerializeField] private TMP_Text areaPercentText;
    [SerializeField] private Image equippedAnimalIcon;

    [Header("Navegação de Secções")]
    [Tooltip("Um TMP_Text por secção (mesma ordem que \"sectionBehaviours\"), usado para realçar a secção actual.")]
    [SerializeField] private List<TMP_Text> sectionLabels = new List<TMP_Text>();
    [SerializeField] private Color sectionInactiveColor = new Color(1f, 1f, 1f, 0.5f);
    [SerializeField] private Color sectionActiveColor = Color.white;

    [Header("Secções (ordem: Área, Diário, Formas, Itens, Progresso, Opções)")]
    [Tooltip("Cada elemento deve ser um componente que implementa IPauseMenuSection.")]
    [SerializeField] private List<MonoBehaviour> sectionBehaviours = new List<MonoBehaviour>();

    [Header("Som (orgânico — folhas/madeira/sino)")]
    [SerializeField] private AudioClip openSfx;
    [SerializeField] private AudioClip closeSfx;
    [SerializeField] private AudioClip pageChangeSfx;

    [Header("Referências")]
    [SerializeField] private PlayerInputRouter input;
    [SerializeField] private FormSwitcher playerFormSwitcher;

    private readonly List<IPauseMenuSection> sections = new List<IPauseMenuSection>();
    private int currentSectionIndex;
    private bool isOpen;
    private Coroutine animRoutine;

    public bool IsOpen => isOpen;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            Destroy(gameObject);
            return;
        }

        Instance = this;

        sections.Clear();
        foreach (var mb in sectionBehaviours)
        {
            if (mb is IPauseMenuSection section)
            {
                sections.Add(section);
                if (section.Root != null) section.Root.SetActive(false);
            }
            else
            {
                Debug.LogError($"[PauseMenuController] '{(mb != null ? mb.name : "null")}' não implementa IPauseMenuSection — ignorado.");
            }
        }

        if (panelRoot != null) panelRoot.SetActive(false);
        if (canvasGroup != null) canvasGroup.alpha = 0f;
    }

    private void Start()
    {
        if (input == null) input = FindFirstObjectByType<PlayerInputRouter>();
        if (playerFormSwitcher == null) playerFormSwitcher = FindFirstObjectByType<FormSwitcher>();
    }

    private void OnEnable()
    {
        if (input == null) input = FindFirstObjectByType<PlayerInputRouter>();
        if (input == null) return;

        input.PausePressed += OnPausePressed;
        input.PrevFormTapped += OnPrevSection;
        input.NextFormTapped += OnNextSection;
    }

    private void OnDisable()
    {
        if (input == null) return;

        input.PausePressed -= OnPausePressed;
        input.PrevFormTapped -= OnPrevSection;
        input.NextFormTapped -= OnNextSection;
    }

    // ---------------- Abrir / Fechar ----------------

    private void OnPausePressed()
    {
        if (isOpen) Close();
        else Open();
    }

    public void Open()
    {
        if (isOpen) return;
        if (sections.Count == 0)
        {
            Debug.LogWarning("[PauseMenuController] Nenhuma secção configurada — menu não abre.");
            return;
        }

        // Task 3.1: exclusão mútua — se o Menu Secundário estiver aberto, fechá-lo
        // antes de abrir a Pausa (a direcção inversa já existe em SecondaryMenuController).
        if (SecondaryMenuController.Instance != null && SecondaryMenuController.Instance.IsOpen)
            SecondaryMenuController.Instance.Close();

        isOpen = true;

        GamePauseUtil.Pause();
        AudioManager.Instance?.SetBgmMuffled(true);

        if (panelRoot != null) panelRoot.SetActive(true);

        RefreshHeader();
        ShowSection(currentSectionIndex, true);

        PlayAnimation(opening: true);
        AudioManager.Instance?.PlaySE(openSfx);
    }

    public void Close()
    {
        if (!isOpen) return;

        isOpen = false;

        if (currentSectionIndex < sections.Count)
            sections[currentSectionIndex].OnHide();

        if (EventSystem.current != null) EventSystem.current.SetSelectedGameObject(null);

        PlayAnimation(opening: false);
        AudioManager.Instance?.PlaySE(closeSfx);
    }

    // ---------------- Navegação de Secções ----------------

    private void OnPrevSection()
    {
        if (!isOpen) return;
        ChangeSection(-1);
    }

    private void OnNextSection()
    {
        if (!isOpen) return;
        ChangeSection(1);
    }

    private void ChangeSection(int delta)
    {
        if (sections.Count <= 1) return;

        int next = (currentSectionIndex + delta + sections.Count) % sections.Count;
        if (next == currentSectionIndex) return;

        sections[currentSectionIndex].OnHide();
        ShowSection(next, refresh: true);

        AudioManager.Instance?.PlaySE(pageChangeSfx);
    }

    private void ShowSection(int index, bool refresh)
    {
        currentSectionIndex = index;

        for (int i = 0; i < sections.Count; i++)
        {
            bool active = i == index;

            if (sections[i].Root != null) sections[i].Root.SetActive(active);

            if (i < sectionLabels.Count && sectionLabels[i] != null)
                sectionLabels[i].color = active ? sectionActiveColor : sectionInactiveColor;
        }

        if (refresh) sections[index].Refresh();
    }

    // ---------------- Cabeçalho ----------------

    private void RefreshHeader()
    {
        var world = WorldState.Instance != null ? WorldState.Instance.CurrentWorld : null;
        var area = WorldState.Instance != null ? WorldState.Instance.CurrentArea : null;

        if (worldNameText != null) worldNameText.text = world != null ? world.displayName : string.Empty;
        if (areaNameText != null) areaNameText.text = area != null ? area.displayName : string.Empty;

        int percent = (area != null && PlayerProgress.Instance != null)
            ? PlayerProgress.Instance.GetAreaCompletionPercent(area)
            : 0;
        if (areaPercentText != null) areaPercentText.text = $"{percent}%";

        var form = playerFormSwitcher != null ? playerFormSwitcher.CurrentForm : null;
        if (equippedAnimalIcon != null)
        {
            equippedAnimalIcon.sprite = form != null ? form.icon : null;
            equippedAnimalIcon.enabled = form != null && form.icon != null;
        }
    }

    /// <summary>
    /// Chamado pelas secções (ex: Área Atual, depois de recolher algo) quando o
    /// progresso muda de forma que afecte o cabeçalho (percentagem da área).
    /// </summary>
    public void RefreshHeader_External() => RefreshHeader();

    /// <summary>
    /// Abre o Menu de Pausa (se ainda fechado) directamente numa secção
    /// específica — ex: a secção Formas, quando uma nova transformação é
    /// libertada (Tarefa #9, "essa tela abre, e aparece a animação do animal
    /// sendo revelado no ramo"). "sectionBehaviour" deve ser um dos elementos
    /// de "sectionBehaviours".
    /// </summary>
    public void OpenToSection(MonoBehaviour sectionBehaviour)
    {
        int index = sectionBehaviours.IndexOf(sectionBehaviour);
        if (index < 0)
        {
            Open();
            return;
        }

        bool wasOpen = isOpen;
        if (!wasOpen) Open();

        if (index != currentSectionIndex)
        {
            sections[currentSectionIndex].OnHide();
            ShowSection(index, refresh: true);
            if (wasOpen) AudioManager.Instance?.PlaySE(pageChangeSfx);
        }
    }

    /// <summary>Toca um som orgânico curto através do AudioManager (ex: madeira ao confirmar, sino ao seleccionar) — usado pelas secções.</summary>
    public void PlaySfx(AudioClip clip) => AudioManager.Instance?.PlaySE(clip);

    // ---------------- Animação ----------------

    private void PlayAnimation(bool opening)
    {
        if (animRoutine != null) StopCoroutine(animRoutine);
        animRoutine = StartCoroutine(AnimateRoutine(opening));
    }

    private IEnumerator AnimateRoutine(bool opening)
    {
        float from = opening ? closedScale : 1f;
        float to = opening ? 1f : closedScale;
        float fromAlpha = opening ? 0f : 1f;
        float toAlpha = opening ? 1f : 0f;

        float t = 0f;
        float duration = Mathf.Max(0.01f, animDuration);

        while (t < duration)
        {
            // Tempo real: o jogo já está pausado (Time.timeScale = 0) enquanto o menu está aberto.
            t += Time.unscaledDeltaTime;
            float p = Mathf.Clamp01(t / duration);
            float eased = 1f - Mathf.Pow(1f - p, 3f); // ease-out cúbico

            if (animatedRoot != null) animatedRoot.localScale = Vector3.one * Mathf.Lerp(from, to, eased);
            if (canvasGroup != null) canvasGroup.alpha = Mathf.Lerp(fromAlpha, toAlpha, eased);

            yield return null;
        }

        if (animatedRoot != null) animatedRoot.localScale = Vector3.one * to;
        if (canvasGroup != null) canvasGroup.alpha = toAlpha;

        if (!opening)
        {
            if (panelRoot != null) panelRoot.SetActive(false);

            // Só retoma o jogo (e o BGM normal) depois da animação de fecho terminar.
            GamePauseUtil.Resume();
            AudioManager.Instance?.SetBgmMuffled(false);
        }
    }
}
